import audit_future_leak_walkforward as audit_mod


class FutureLeakWalkforwardAuditTests(unittest.TestCase):
    def test_audit_windows_passes_for_strictly_ordered_windows(self) -> None:
        issues = audit_mod.audit_windows(
            [
                {
                    "train_start": "2015-01-05",
                    "train_end": "2020-12-31",
                    "valid_start": "2021-01-04",
                    "valid_end": "2022-12-30",
                    "test_start": "2023-01-03",
                    "test_end": "2023-06-30",
                },
                {
                    "train_start": "2015-04-01",
                    "train_end": "2021-03-31",
                    "valid_start": "2021-04-01",
                    "valid_end": "2023-03-31",
                    "test_start": "2023-07-03",
                    "test_end": "2023-12-29",
                },
            ]
        )
        self.assertEqual(issues, [])

    def test_audit_windows_detects_overlap(self) -> None:
        issues = audit_mod.audit_windows(
            [
                {
                    "train_start": "2015-01-05",
                    "train_end": "2020-12-31",
                    "valid_start": "2021-01-04",
                    "valid_end": "2022-12-30",
                    "test_start": "2023-01-03",
                    "test_end": "2023-06-30",
                },
                {
                    "train_start": "2015-04-01",
                    "train_end": "2021-03-31",
                    "valid_start": "2021-04-01",
                    "valid_end": "2023-03-31",
                    "test_start": "2023-06-15",
                    "test_end": "2023-12-29",
                },
            ]
        )
        self.assertTrue(any("test_overlap" in issue for issue in issues))

    def test_validate_signal_trade_order_rejects_same_day_or_later(self) -> None:
        with self.assertRaisesRegex(ValueError, "signal_date must be earlier than trade_date"):
            audit_mod.validate_signal_trade_order("2026-03-12", "2026-03-12")


